// Helper to get the status icon for file indicators
const getStatusIcon = (status: FileStatus) => {
  switch (status) {
    case 'added':
      return Plus
    case 'removed':
      return Minus
    case 'modified':
      return Circle
    case 'unchanged':
      return Circle
    default:
      return Circle
  }
}

